+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; size: number}
+	| {kind: 'auto'}
+	| {kind: 'fr'; fraction: number}
+	| {kind: 'minmax'; min: number; max: number | {fraction: number}};
+
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const trackPattern = /minmax\\([^)]*\\)|\\S+/g;
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+
+	return (template.match(trackPattern) ?? []).map(value => {
+		if (value === 'auto') return {kind: 'auto'};
+		const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+		if (fr) return {kind: 'fr', fraction: Number(fr[1])};
+		const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+|\\d*\\.?\\d+fr)\\s*\\)$/.exec(value);
+		if (minmax) {
+			const maximum = minmax[2]!;
+			const maxFr = /^(\\d*\\.?\\d+)fr$/.exec(maximum);
+			return {
+				kind: 'minmax',
+				min: Number(minmax[1]),
+				max: maxFr ? {fraction: Number(maxFr[1])} : Number(maximum),
+			};
+		}
+
+		const size = Number(value);
+		if (!Number.isNaN(size)) return {kind: 'fixed', size};
+		throw new Error(`Invalid grid track size: ${value}`);
+	});
+};
+
+const parseLine = (value: number | string | undefined): [number | undefined, number | undefined] => {
+	if (typeof value === 'number') return [value, value + 1];
+	if (!value) return [undefined, undefined];
+	const parts = value.split('/').map(part => Number(part.trim()));
+	if (parts.length === 1 && Number.isFinite(parts[0])) return [parts[0], parts[0]! + 1];
+	if (parts.length === 2 && parts.every(Number.isFinite)) return [parts[0], parts[1]];
+	throw new Error(`Invalid grid placement: ${value}`);
+};
+
+const overlaps = (a: Placement, b: Placement): boolean =>
+	a.column < b.columnEnd && a.columnEnd > b.column && a.row < b.rowEnd && a.rowEnd > b.row;
+
+const placeChildren = (children: DOMElement[], columns: number): Placement[] => {
+	const placements: Placement[] = [];
+	let cursorColumn = 1;
+	let cursorRow = 1;
+
+	for (const child of children) {
+		let [column, columnEnd] = parseLine(child.style.gridColumn);
+		let [row, rowEnd] = parseLine(child.style.gridRow);
+		const columnSpan = columnEnd && column ? Math.max(1, columnEnd - column) : 1;
+		const rowSpan = rowEnd && row ? Math.max(1, rowEnd - row) : 1;
+		if (column && !columnEnd) columnEnd = column + 1;
+		if (row && !rowEnd) rowEnd = row + 1;
+
+		if (!column || !row) {
+			let candidateColumn = column ?? cursorColumn;
+			let candidateRow = row ?? cursorRow;
+			while (true) {
+				if (!column && candidateColumn + columnSpan - 1 > columns) {
+					candidateColumn = 1;
+					candidateRow++;
+				}
+				const candidate: Placement = {
+					column: candidateColumn,
+					columnEnd: candidateColumn + columnSpan,
+					row: candidateRow,
+					rowEnd: candidateRow + rowSpan,
+				};
+				if (!placements.some(existing => overlaps(existing, candidate))) {
+					column ??= candidate.column;
+					columnEnd ??= candidate.columnEnd;
+					row ??= candidate.row;
+					rowEnd ??= candidate.rowEnd;
+					break;
+				}
+				if (column) candidateRow++;
+				else candidateColumn++;
+			}
+		}
+
+		const placement = {column: column!, columnEnd: columnEnd!, row: row!, rowEnd: rowEnd!};
+		placements.push(placement);
+		cursorColumn = placement.columnEnd;
+		cursorRow = placement.row;
+		if (cursorColumn > columns) {
+			cursorColumn = 1;
+			cursorRow++;
+		}
+	}
+
+	return placements;
+};
+
+const resolveTracks = (tracks: Track[], available: number, gap: number, intrinsic: number[]): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.kind === 'fixed') return track.size;
+		if (track.kind === 'auto') return intrinsic[index] ?? 0;
+		if (track.kind === 'minmax' && typeof track.max === 'number') return Math.max(track.min, Math.min(track.max, intrinsic[index] ?? track.min));
+		if (track.kind === 'minmax') return track.min;
+		return 0;
+	});
+	const fractions = tracks.reduce((total, track) => total + (track.kind === 'fr' ? track.fraction : track.kind === 'minmax' && typeof track.max !== 'number' ? track.max.fraction : 0), 0);
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - sizes.reduce((total, size) => total + size, 0));
+	if (fractions > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.kind === 'fr') sizes[index] = remaining * track.fraction / fractions;
+			if (track.kind === 'minmax' && typeof track.max !== 'number') sizes[index] += remaining * track.max.fraction / fractions;
+		}
+	}
+	return sizes;
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	if (node.style.display !== 'grid' || !node.yogaNode || children.length === 0) return;
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns.push({kind: 'auto'});
+	const rows = parseTracks(node.style.gridTemplateRows);
+	const placements = placeChildren(children, columns.length);
+	const rowCount = Math.max(rows.length, ...placements.map(placement => placement.rowEnd - 1));
+	while (rows.length < rowCount) rows.push({kind: 'auto'});
+	const layout = node.yogaNode.getComputedLayout();
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const columnIntrinsic = Array.from({length: columns.length}, () => 0);
+	const rowIntrinsic = Array.from({length: rows.length}, () => 0);
+	for (const [index, child] of children.entries()) {
+		const childLayout = child.yogaNode!.getComputedLayout();
+		const placement = placements[index]!;
+		if (placement.columnEnd - placement.column === 1) columnIntrinsic[placement.column - 1] = Math.max(columnIntrinsic[placement.column - 1]!, childLayout.width);
+		if (placement.rowEnd - placement.row === 1) rowIntrinsic[placement.row - 1] = Math.max(rowIntrinsic[placement.row - 1]!, childLayout.height);
+	}
+	const columnSizes = resolveTracks(columns, layout.width, columnGap, columnIntrinsic);
+	const naturalHeight = rowIntrinsic.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rows.length - 1);
+	const rowSizes = resolveTracks(rows, node.style.height === undefined ? naturalHeight : layout.height, rowGap, rowIntrinsic);
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+	if (node.style.height === undefined) node.yogaNode.setHeight(rowSizes.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rows.length - 1));
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index]!;
+		const left = columnOffsets[placement.column - 1]!;
+		const top = rowOffsets[placement.row - 1]!;
+		const width = columnOffsets[placement.columnEnd - 1]! + columnSizes[placement.columnEnd - 1]! - left - columnGap;
+		const height = rowOffsets[placement.rowEnd - 1]! + rowSizes[placement.rowEnd - 1]! - top - rowGap;
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, left);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, top);
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height);
+	}
+};
+
+const visit = (node: DOMElement): void => {
+	layoutGrid(node);
+	for (const child of node.childNodes) if (child.nodeName !== '#text') visit(child);
+};
+
+export const calculateLayout = (root: DOMElement, width: number): void => {
+	root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	visit(root);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+};
